Set-StrictMode -Version 2.0
function New-GodModeMissionObject { param([string]$Id,[string]$Role,[string]$Task,[bool]$AllowPatch=$false,[bool]$RequiresBrowserValidation=$false,[int]$Priority=5) @{schema_version=1;id=$Id;role=$Role;task=$Task;mode='safe';model='auto';priority=$Priority;created_at=Get-GodModeIso;parent_mission_id=$null;required_baseline=$null;max_iterations=1;allow_patch=$AllowPatch;requires_validation=$true;requires_browser_validation=$RequiresBrowserValidation;requires_live_preview=$false;tournament=$false;adversarial_review=$false;generation_depth=0;parent_chain=@();mission_signature=($Role+':'+$Task).ToLowerInvariant();budget_policy=@{};network_allowed=$false;apply_to_main=$false;journey_id=$null} }
function Save-GodModeMission { param([string]$Project='.',[hashtable]$Mission,[string]$Queue='pending') $r=Initialize-GodModeStructure $Project; $p=Join-GodModePath $r ("queues/$Queue/$($Mission.id).json"); Write-GodModeJsonAtomic $p $Mission|Out-Null; $p }
function Submit-GodModeAgentResult { param([string]$Project='.',[hashtable]$Result) $r=Initialize-GodModeStructure $Project; $p=Join-GodModePath $r ("inbox/results/$($Result.mission_id).json"); Write-GodModeJsonAtomic $p $Result|Out-Null; $p }
function Get-GodModeQueueDepth { param([string]$Project='.') $r=Initialize-GodModeStructure $Project; $d=@{}; foreach($q in @('pending','active','done','failed','replay','tournament','adversarial')){ $d[$q]=@(Get-ChildItem (Join-GodModePath $r ("queues/$q")) -Filter '*.json' -ErrorAction SilentlyContinue).Count }; $d }
